const cco_docs_err_msg = 'Something went wrong! Please try after sometime.';

function cco_docs_loader(count = '', df = false) {

    if( !df ) count = (count != '') ? ('Uploading: <span class="font-bold">'+ count +'%</span>') : 'Uploading...';
    return '<span class="cco-docs-upload-loader">'+ count +'</span>';
}

function check_span_in_container(res_container) {
    if (res_container.find('span').length)
        res_container.find('span').remove();
}

function cco_docs_upload(c_btn, res_container, form, fileInput, annex = false)
{
    fileInput.click();
    var actionURL = form.attr("data-action");

    fileInput.off('change').on('change', function() {

        if (this.files.length > 0) {

            var ccoDocFile = this.files[0];
            check_span_in_container(res_container); // function call

            // check file type and size // Check if file is selected
            if (!ccoDocFile) {
                res_container.append( '<span class="d-block text-danger font-sm mt-2">Please select a file.</span>' );
                return;
            }

            if (!cco_docs_type.includes(ccoDocFile.type)) {
                res_container.append( '<span class="d-block text-danger font-sm mt-2">Only '+ cco_docs_type +' files are allowed.</span>' );
                return;
            }

            var docMaxSize = cco_docs_size * 1024 * 1024; // 10 MB (adjust as needed)

            if (ccoDocFile.size > docMaxSize) {
                res_container.append( '<span class="d-block text-danger font-sm mt-2">File size exceeds the maximum limit of '+ cco_docs_size +' MB.</span>' );
                return;
            }

            var formData = new FormData(form[0]);

            formData.append('doc_cat_type', c_btn.attr('data-doc_cat_type'));

            if( c_btn.attr('data-circulr_id') )
                formData.append('circulr_id', c_btn.attr('data-circulr_id'));

            if( c_btn.attr('data-task_id') )
                formData.append('task_id', c_btn.attr('data-task_id'));

            if( c_btn.attr('data-ans_id') )
                formData.append('ans_id', c_btn.attr('data-ans_id'));

            if( c_btn.attr('data-annex_id') )
                formData.append('annex_id', c_btn.attr('data-annex_id'));

            if( c_btn.attr('data-com_asses_id') )
                formData.append('com_asses_id', c_btn.attr('data-com_asses_id'));

            if( c_btn.attr('data-submit_auth_id') )
                formData.append('submit_auth_id', c_btn.attr('data-submit_auth_id'));

            res_container.append( cco_docs_loader('0') );

            $.ajax({
                url: actionURL,
                type: 'POST',
                data: formData,
                contentType: false,
                processData: false,
                xhr: function() {
                    var xhr = new window.XMLHttpRequest();
                    xhr.upload.addEventListener('progress', function(e) {
                        if (e.lengthComputable) {
                            var percentComplete = e.loaded / e.total * 100;
                            res_container.append( cco_docs_loader(percentComplete) );
                        }
                    }, false);
                    return xhr;
                },

                success: function(res) {

                    check_span_in_container(res_container); // function call

                    try 
                    {
                        res = JSON.parse(res);
                
                        // has error
                        if(res.err)
                            res_container.append( '<span class="d-block text-danger font-sm mt-2">'+ res.msg +'</span>' );
                        else
                        {
                            // display markup
                            res_container.append( res.markup );
                        }

                    } 
                    catch (error) { alert(cco_docs_err_msg); }
                },
                
                error: function() { alert(cco_docs_err_msg); }
            });

        }

        fileInput.val('');
    });
}

$(document).ready(function() {

    const ccoDocsForm = $('#com_docs_upload_form');
    const ccoDocsFileInput = $('#com_docs_file');

    if( ccoDocsForm &&
        ccoDocsFileInput &&
        $('.cco-docs-upload-btn').length > 0 )
    {
        $('.cco-docs-upload-btn').on('click', function() {

            const cBtn = $(this);
            const res_container = cBtn.parent().find('.cco-docs-upload-container');

            if( cco_docs_type !== undefined && 
                cco_docs_size !== undefined && 
                res_container )
            {
                if(cBtn.attr('data-doc_cat_type') != undefined)
                {
                    check_span_in_container(res_container); // function call
                    res_container.append( cco_docs_loader() );

                    // function call
                    cco_docs_upload(cBtn, res_container, ccoDocsForm, ccoDocsFileInput);
                }
                else
                {
                    check_span_in_container(res_container); // function call
                    res_container.append( '<span class="d-block text-danger font-sm mt-2">'+ cco_docs_err_msg +'</span>' );
                }
            }
            else
                alert(cco_docs_err_msg);
        });
    }

    $(document).delegate('.remove-com-docs-upload', 'click', function() {

        if(confirm('Are you sure? you want to delete.'))
        {
            const link = $(this);
            const container = link.closest('.cco-docs-uploader');
            const res_container = container.parent();
            check_span_in_container(res_container); // function call

            if(container != undefined)
            {
                $.ajax({
                    url: link.attr('href'),
                    type: 'GET',
                    success: function(res) {

                        try 
                        {
                            res = JSON.parse(res);
                    
                            // has error
                            if(res.err)
                                $( res_container ).append('<span class="d-block text-danger font-sm mt-2">'+ res.msg +'</span>');
                            else
                            {
                                // display markup
                                $( res_container ).append('<span class="d-block text-success font-sm mt-2">'+ res.msg +'</span>');
                                container.remove();
                            }

                        } 
                        catch (error) { alert(cco_docs_err_msg); }
                    },
                    
                    error: function() { alert(cco_docs_err_msg); }
                });
            }
            else
                alert(cco_docs_err_msg);
        }  

        return false;
    });

});